return-response.set-body:
@{
                try 
                {
                    string xmlContent = context.Request.Body?.As(preserveContent: true);
                    if (string.IsNullOrEmpty(xmlContent))
                    {
                        return "{\"error\": \"请求体为空\"}";
                    }

                    // 使用 APIM 支持的 XML 解析方法
                    System.Xml.XmlDocument doc = new System.Xml.XmlDocument();
                    doc.LoadXml(xmlContent);

                    // 直接调用转换函数（在同一个代码块中定义）
                    return ConvertXmlToJson(doc.DocumentElement);
                }
                catch (System.Xml.XmlException)
                {
                    return "{\"error\": \"XML格式不正确\"}";
                }
                catch (Exception ex)
                {
                    return $"{{\"error\": \"处理失败: {ex.Message}\"}}";
                }

                // XML 到 JSON 转换函数
                string ConvertXmlToJson(System.Xml.XmlNode node)
                {
                    if (node == null) return "null";

                    // 如果是文本节点，直接返回值
                    if (node is System.Xml.XmlText || node is System.Xml.XmlCDataSection)
                    {
                        return $"\"{EscapeJsonString(node.Value)}\"";
                    }

                    // 如果是元素节点
                    if (node is System.Xml.XmlElement)
                    {
                        var element = (System.Xml.XmlElement)node;
                        var childNodes = element.ChildNodes;

                        // 如果没有子节点，返回空对象或值
                        if (childNodes.Count == 0)
                        {
                            return "{}";
                        }

                        // 如果只有一个文本子节点，当作简单值处理
                        if (childNodes.Count == 1 && (childNodes[0] is System.Xml.XmlText || childNodes[0] is System.Xml.XmlCDataSection))
                        {
                            return $"\"{EscapeJsonString(childNodes[0].Value)}\"";
                        }

                        // 处理多个子节点
                        var json = "{";
                        var childrenProcessed = 0;

                        foreach (System.Xml.XmlNode child in childNodes)
                        {
                            if (child is System.Xml.XmlElement)
                            {
                                if (childrenProcessed > 0) json += ",";
                                json += $"\"{child.Name}\":{ConvertXmlToJson(child)}";
                                childrenProcessed++;
                            }
                        }

                        json += "}";
                        return json;
                    }

                    return "{}";
                }

                // JSON 字符串转义函数
                string EscapeJsonString(string s)
                {
                    if (string.IsNullOrEmpty(s)) return "";
                    return s.Replace("\\", "\\\\")
                            .Replace("\"", "\\\"")
                            .Replace("\b", "\\b")
                            .Replace("\f", "\\f")
                            .Replace("\n", "\\n")
                            .Replace("\r", "\\r")
                            .Replace("\t", "\\t");
                }
            }

inbound.log-to-eventhub:
@{
                return new JObject(
                    new JProperty("EventTime", DateTime.UtcNow.ToString()),
                    new JProperty("ServiceName", context.Deployment.ServiceName),
                    new JProperty("RequestId", context.RequestId),
                    new JProperty("RequestIp", context.Request.IpAddress),
                    new JProperty("OperationName", context.Operation.Name)
                ).ToString();
            }
